import { useState } from 'react';
import { ChevronDown, Shield, Brain, Globe, BarChart2, Network, ChevronUp } from 'lucide-react';
import SectionHeader from './SectionHeader';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';

const groupsData = [
  {
    key:'cyber', icon:<Shield size={15}/>, accent:'#2a9d8f', glow:'rgba(42,157,143,0.22)',
    certs:[
      { org:'Google / Coursera', name:'Foundations of Cybersecurity',                  date:'Dec 2025', img:'/assets/certs/google_cyber_1_foundations.jpg' },
      { org:'Google / Coursera', name:'Play It Safe: Manage Security Risks',            date:'Feb 2026', img:'/assets/certs/google_cyber_2_security_risks.jpg' },
      { org:'Google / Coursera', name:'Connect & Protect: Networks & Security',         date:'Mar 2026', img:'/assets/certs/google_cyber_3_networks.jpg' },
      { org:'Google / Coursera', name:'Tools of the Trade: Linux and SQL',              date:'Mar 2026', img:'/assets/certs/google_cyber_4_linux_sql.jpg' },
      { org:'Google / Coursera', name:'Assets, Threats, and Vulnerabilities',           date:'Mar 2026', img:'/assets/certs/google_cyber_5_assets.jpg' },
      { org:'Google / Coursera', name:'Sound the Alarm: Detection & Response',          badge:'🔄 6/9',  img:null },
      { org:'Sprints × Microsoft', name:'Cybersecurity Summer Camp (40 hrs)',            date:'2024',    img:null },
      { org:'HP LIFE',             name:'Cybersecurity Awareness',                       img:null },
    ],
  },
  {
    key:'ai', icon:<Brain size={15}/>, accent:'#f0a500', glow:'rgba(240,165,0,0.22)',
    certs:[
      { org:'NVIDIA Academy', name:'AI for All: From Basics to GenAI Practice',          date:'Jan 2026', img:'/assets/certs/nvidia_genai.jpg' },
      { org:'NVIDIA Academy', name:'Building LLM Applications with Prompt Engineering',  date:'Feb 2026', img:'/assets/certs/nvidia_llm.jpg' },
      { org:'IBM / Coursera', name:'Introduction to Artificial Intelligence',            date:'Feb 2025', img:'/assets/certs/ibm_intro_ai.jpg' },
      { org:'IBM / Coursera', name:'Delivering Quality Work with Agility',               date:'Jan 2026', img:'/assets/certs/ibm_agility.jpg' },
      { org:'Dubai Future Foundation', name:'AI Prompt Engineering — 1M Prompters',     img:'/assets/certs/dubai-ai.jpg' },
      { org:'HP LIFE',        name:'Data Science & Analytics',                           img:null },
    ],
  },
  {
    key:'net', icon:<Network size={15}/>, accent:'#4d8fff', glow:'rgba(77,143,255,0.22)',
    certs:[
      { org:'Cisco Networking Academy', name:'Networking Basics', date:'Jul 2025', img:'/assets/certs/cisco_networking.jpg' },
    ],
  },
  {
    key:'digital', icon:<Globe size={15}/>, accent:'#e76f51', glow:'rgba(231,111,81,0.22)',
    certs:[
      { org:'Google',              name:'Digital Marketing Fundamentals',          img:'/assets/certs/google_digital_mktg.jpg' },
      { org:'Banque Misr × Google',name:'Maharat min Google — Digital Marketing',  img:'/assets/certs/google-maharat.jpg' },
      { org:'HP LIFE',             name:'Digital Business Skills',                 img:null },
    ],
  },
  {
    key:'tech', icon:<BarChart2 size={15}/>, accent:'#a855f7', glow:'rgba(168,85,247,0.22)',
    certs:[
      { org:'Meta / Coursera',   name:'Introduction to Data Analytics',   date:'Sep 2024', img:'/assets/certs/meta_data_analytics.jpg' },
      { org:'ITI Mahara-Tech',   name:'Python Programming Basics',         date:'Nov 2025', img:'/assets/certs/iti_python.jpg' },
      { org:'EYouth Learning',   name:'Blockchain Technology',             img:'/assets/certs/eyouth.jpg' },
      { org:'LinkedIn Learning', name:'Sustainability Foundations',         date:'Aug 2025', img:'/assets/certs/linkedin_sustainability.jpg' },
    ],
  },
];

const groupLabels = {
  en: { cyber:'Cybersecurity — Google 6/9 🔄', ai:'AI & Gen AI', net:'Networking', digital:'Digital & Marketing', tech:'Tech & Other' },
  ar: { cyber:'الأمن السيبراني — Google 6/9 🔄', ai:'الذكاء الاصطناعي', net:'الشبكات', digital:'التسويق الرقمي', tech:'التقنية وغيرها' },
};

function CertItem({ c, accent, glow, dark }) {
  const [expanded, setExpanded] = useState(false);

  // Solid visible background
  const itemBg   = dark ? 'rgba(255,255,255,0.07)' : 'rgba(255,255,255,0.85)';
  const itemBord = dark ? 'rgba(255,255,255,0.12)' : 'rgba(26,26,46,0.10)';
  const ink      = dark ? '#f0f0f8' : '#1a1a2e';
  const muted    = dark ? 'rgba(255,255,255,0.45)' : '#8a8a9a';

  return (
    <div className="rounded-xl overflow-hidden transition-all duration-300"
      style={{
        background: itemBg,
        border: `1px solid ${expanded ? accent + '44' : itemBord}`,
        backdropFilter: 'blur(16px)', WebkitBackdropFilter: 'blur(16px)',
        boxShadow: expanded ? `0 6px 24px ${glow}` : '0 2px 8px rgba(0,0,0,0.06)',
      }}>
      <div className="flex items-start justify-between px-4 py-3 gap-2 cursor-pointer"
        onClick={() => c.img && setExpanded(!expanded)}>
        <div className="flex-1 min-w-0">
          <p className="text-[.6rem] font-semibold tracking-wider uppercase mb-1" style={{ color: accent }}>{c.org}</p>
          <p className="text-[.84rem] font-semibold leading-snug" style={{ color: ink }}>{c.name}</p>
          {c.date && <p className="text-[.63rem] mt-0.5" style={{ color: muted }}>{c.date}</p>}
          {c.badge && <span className="inline-block text-[.6rem] font-semibold px-2 py-0.5 rounded-full mt-1" style={{ background:`${accent}15`, color:accent, border:`1px solid ${accent}30` }}>{c.badge}</span>}
        </div>
        {c.img && (
          <div className="w-6 h-6 rounded-full flex-shrink-0 flex items-center justify-center mt-0.5 transition-all"
            style={{ background:`${accent}15`, color:accent }}>
            {expanded ? <ChevronUp size={12}/> : <ChevronDown size={12}/>}
          </div>
        )}
      </div>

      {expanded && c.img && (
        <div className="px-4 pb-4" style={{ animation:'fadeUp .2s ease both' }}>
          <div className="rounded-xl overflow-hidden border" style={{ borderColor:`${accent}30` }}>
            <img src={c.img} alt={c.name} className="w-full object-contain max-h-[280px]" loading="lazy"/>
          </div>
        </div>
      )}
    </div>
  );
}

export default function Certs() {
  const { dark, lang } = useApp();
  const tr     = t[lang];
  const [open, setOpen] = useState(0);
  const labels = groupLabels[lang];
  const bg     = dark ? '#13131e' : '#f5f0e8';

  return (
    <section id="certs" style={{ background: bg }} className="py-24 px-[5%] transition-colors duration-300">
      <SectionHeader tag={tr.certsTag} title={tr.certsTitle} />
      <p className="text-sm mb-8 -mt-6" style={{ color: dark ? 'rgba(255,255,255,0.35)' : '#8a8a9a' }}>
        {lang === 'ar' ? 'اضغط الفئة لتوسيعها · اضغط الشهادة لعرض صورتها' : 'Click category to expand · Click cert to preview'}
      </p>

      <div className="flex flex-col gap-2.5 max-w-3xl">
        {groupsData.map((g, gi) => {
          const isOpen = open === gi;
          // Group button — solid and visible
          const btnBg   = isOpen ? `${g.accent}15` : dark ? 'rgba(255,255,255,0.07)' : 'rgba(255,255,255,0.85)';
          const btnBord = isOpen ? `${g.accent}38` : dark ? 'rgba(255,255,255,0.12)' : 'rgba(26,26,46,0.10)';
          const btnClr  = isOpen ? g.accent : dark ? 'rgba(255,255,255,0.75)' : '#1a1a2e';

          return (
            <div key={gi} className="reveal" style={{ transitionDelay: `${gi * 0.06}s` }}>
              <button
                onClick={() => setOpen(isOpen ? null : gi)}
                className="w-full flex items-center justify-between px-5 py-4 rounded-2xl transition-all duration-250"
                style={{
                  background: btnBg,
                  border: `1px solid ${btnBord}`,
                  backdropFilter: 'blur(16px)', WebkitBackdropFilter:'blur(16px)',
                  color: btnClr,
                  boxShadow: isOpen ? `0 8px 28px ${g.glow}` : '0 2px 8px rgba(0,0,0,0.06)',
                }}>
                <div className="flex items-center gap-3">
                  <span style={{ color: isOpen ? g.accent : dark ? 'rgba(255,255,255,0.5)' : '#8a8a9a' }}>{g.icon}</span>
                  <span className="font-semibold text-sm">{labels[g.key]}</span>
                  <span className="text-xs opacity-50">({g.certs.length})</span>
                </div>
                <ChevronDown size={15}
                  style={{ color: g.accent, transform: isOpen ? 'rotate(180deg)' : 'rotate(0)', transition:'transform .3s' }}/>
              </button>

              {isOpen && (
                <div className="mt-2 flex flex-col gap-2 pl-2">
                  {g.certs.map((c, ci) => (
                    <div key={ci} style={{ animation:`fadeUp .22s ${ci*0.04}s ease both` }}>
                      <CertItem c={c} accent={g.accent} glow={g.glow} dark={dark}/>
                    </div>
                  ))}
                </div>
              )}
            </div>
          );
        })}
      </div>
    </section>
  );
}
